package app.venues.organization.domain
enum class OrganizationType { /** * Government ministry or department managing cultural venues. */ GOVERNMENT,
/** * Non-profit organization or foundation. */ NON_PROFIT,
/** * Private company or corporation. */ PRIVATE,
/** * Municipal/city government entity. */ MUNICIPAL,
/** * University or educational institution. */ EDUCATIONAL,
/** * Other type of organization. */ OTHER }

